import React from 'react';
import './App.css'; 
import 'bootstrap/dist/css/bootstrap.min.css'; // Bootstrap वापरा

function App() {
  return (
    <div className="App">
      {/* Navigation */}
      <nav className="navbar navbar-expand-lg navbar-dark bg-dark">
        <div className="container">
          <a className="navbar-brand fw-bold" href="#">FreelancePort</a>
        </div>
      </nav>

      {/* Hero Section */}
      <header className="hero-section text-center">
        <div className="container">
          <h1 className="display-4 fw-bold">Hi, I'm a Student Freelancer</h1>
          <p className="lead">I build professional websites for your business.</p>
          <button className="btn btn-light btn-lg mt-3">Hire Me</button>
        </div>
      </header>

      {/* Skills Section */}
      <section className="container py-5">
        <h2 className="text-center mb-5">My Services</h2>
        <div className="row">
          <div className="col-md-4">
            <div className="card service-card p-4 text-center">
              <h3>Web Design</h3>
              <p>Modern and responsive UI/UX designs.</p>
            </div>
          </div>
          {/* Add more cards here */}
        </div>
      </section>
    </div>
  );
}

export default App;
